import streamlit as stimport plotly.graph_objects as goimport numpy as npfrom utils.data_utils import load_dataset, get_risk_label, get_risk_colorfrom utils.model_utils import load_model, build_input_row, predictfrom utils.crm_utils import get_crm_action, get_compensationfrom config import JOURS, MOIS_Ldef render():    st.markdown("""    <div class='page-header'>        <h1>🎯 Prédiction de Retard</h1>        <p>Analysez le risque d'un vol en temps réel</p>    </div>""", unsafe_allow_html=True)    model  = load_model()    # Curseur dans la sidebar pour la taille de l'échantillon de référence    with st.sidebar:        st.markdown("### ⚙️ Configuration")        sample_size = st.slider(            "Taille de l'échantillon pour les listes déroulantes",            min_value=5000, max_value=100000, value=50000, step=5000,            help="Plus c'est grand, plus les listes de compagnies/aéroports sont complètes, mais plus l'application consomme de mémoire."        )    with st.spinner(f"Chargement d'un échantillon de {sample_size:,} vols pour les listes déroulantes..."):        df_ref = load_dataset(sample_size=sample_size)    compagnies = sorted(df_ref["COMPAGNIE"].dropna().unique())    aeroports  = sorted(df_ref["AP_DEP"].dropna().unique())    pays_list  = sorted(df_ref["PAYS_DEP"].dropna().unique())    st.markdown("### ✈️ Paramètres du vol")    c1,c2,c3 = st.columns(3)    with c1:        st.markdown("**Départ**")        ap_dep   = st.selectbox("Aéroport départ", aeroports, key="ap_dep")        pays_dep = st.selectbox("Pays départ", pays_list, key="pays_dep")        heure    = st.slider("Heure de départ", 0, 23, 10)        mois     = st.selectbox("Mois", range(1,13), format_func=lambda x: MOIS_L[x-1])    with c2:        st.markdown("**Arrivée**")        ap_arr   = st.selectbox("Aéroport arrivée", [a for a in aeroports if a!=ap_dep], key="ap_arr")        pays_arr = st.selectbox("Pays arrivée", pays_list, key="pays_arr")        distance = st.number_input("Distance (km)", 50, 15000, 1200)        jour_sem = st.selectbox("Jour", range(7), format_func=lambda x: JOURS[x])    with c3:        st.markdown("**Opérationnel**")        compagnie = st.selectbox("Compagnie (code)", compagnies)        temps_vol = st.number_input("Temps de vol (min)", 30, 800, 150)        taxi_time = st.number_input("Taxi time (min)", 0, 120, 20)    # Coordonnées depuis les données réelles (recherche dans df_ref)    try:        ri = df_ref[df_ref["AP_DEP"]==ap_dep].iloc[0]        lat_dep,lon_dep,h_dep = ri["LAT_DEP"],ri["LON_DEP"],ri.get("HAUTEUR_DEP",50)    except Exception:        lat_dep,lon_dep,h_dep = 48.8,2.3,50    try:        ra = df_ref[df_ref["AP_ARR"]==ap_arr].iloc[0]        lat_arr,lon_arr,h_arr = ra["LAT_ARR"],ra["LON_ARR"],ra.get("HAUTEUR_ARR",50)    except Exception:        lat_arr,lon_arr,h_arr = 51.5,-0.1,50    st.markdown("<br>", unsafe_allow_html=True)    if st.button("🚀 Analyser le risque de retard", use_container_width=True):        input_df = build_input_row(            ap_dep=ap_dep, ap_arr=ap_arr, compagnie=compagnie,            pays_dep=pays_dep, pays_arr=pays_arr,            heure_h=heure, mois=mois, jour_sem=jour_sem,            distance=distance, taxi_time=taxi_time, temps_vol=temps_vol,            hauteur_dep=float(h_dep), hauteur_arr=float(h_arr),            lat_dep=float(lat_dep), lon_dep=float(lon_dep),            lat_arr=float(lat_arr), lon_arr=float(lon_arr),        )        proba, classe, top_feats = predict(model, input_df)        st.session_state["last_prediction"] = {            "proba":proba,"classe":classe,"compagnie":compagnie,            "ap_dep":ap_dep,"ap_arr":ap_arr,"distance":distance,        }        label,css   = get_risk_label(proba)        color       = get_risk_color(proba)        action_crm  = get_crm_action(proba, distance)        st.markdown("---")        st.markdown("### 📊 Résultat")        rc1,rc2,rc3 = st.columns([2,2,3])        with rc1:            fig_g = go.Figure(go.Indicator(                mode="gauge+number",                value=proba*100,                number={"suffix":"%","font":{"size":36,"color":color}},                gauge={"axis":{"range":[0,100]},"bar":{"color":color,"thickness":0.25},                       "steps":[{"range":[0,25],"color":"rgba(46,204,113,0.15)"},                                 {"range":[25,50],"color":"rgba(243,156,18,0.15)"},                                 {"range":[50,75],"color":"rgba(230,126,34,0.15)"},                                 {"range":[75,100],"color":"rgba(231,76,60,0.15)"}]},                title={"text":"Probabilité de retard","font":{"color":"#F0F4F8"}},            ))            fig_g.update_layout(height=250,                                plot_bgcolor="rgba(0,0,0,0)",paper_bgcolor="rgba(0,0,0,0)",                                font_color="#F0F4F8",margin=dict(t=60,b=10,l=20,r=20))            st.plotly_chart(fig_g, use_container_width=True)        with rc2:            nom_comp = df_ref[df_ref["COMPAGNIE"]==compagnie]["NOM_COMPAGNIE"].iloc[0] \                if len(df_ref[df_ref["COMPAGNIE"]==compagnie]) > 0 else compagnie            st.markdown(f"""            <div class='risk-card {css}'>                <div style='font-size:2rem;margin-bottom:8px;'>{label}</div>                <div style='color:#6B7280;font-size:0.85rem;text-transform:uppercase;'>Niveau de risque</div>                <hr style='border-color:#1F2937;margin:12px 0;'>                <div style='font-size:0.9rem;line-height:1.6;'>                    <b>Action :</b><br>{action_crm['action']}<br><br>                    <b>Canaux :</b> {', '.join(action_crm['canal']) or 'Aucun'}<br>                    <b>Miles offerts :</b> {action_crm['miles']:,}<br>                    <b>Compagnie :</b> {nom_comp}                </div>            </div>""", unsafe_allow_html=True)        with rc3:            st.markdown("**💬 Message CRM**")            st.info(action_crm["message"])            comp_res = get_compensation(distance, 0)            if comp_res["eligible"]:                st.warning(f"⚖️ CE 261/2004 : **{comp_res['montant']} €** — {comp_res['motif']}")        if top_feats:            st.markdown("### 🔍 Facteurs de risque")            cols_f = st.columns(min(len(top_feats),5))            for i,(name,val,_) in enumerate(top_feats[:5]):                with cols_f[i]:                    clean = name.split("__")[-1][:18]                    st.metric(clean, f"{val:.3f}")